	NSDirectory::DeleteDirectory(m_sFileDir);
	m_sFileDir = L"";
	m_nFileType = -1;

	std::wstring sErrorLog = L"open file error (" + std::to_wstring(nReturnCode) + L")";
	CV8RealTimeWorker::_LOGGING_ERROR_(L"error: ", sErrorLog);
	return nReturnCode;
}

